// Chatbot page overlay — shows dark backdrop when chatbot is open
(function() {
  var overlay = document.createElement('div');
  overlay.id = 'chatbotOverlay';
  overlay.className = 'srt-chatbot-overlay';
  document.body.appendChild(overlay);

  var chatWindow = document.getElementById('chatbotWindow');
  if (!chatWindow) return;

  new MutationObserver(function() {
    if (chatWindow.classList.contains('open')) {
      overlay.classList.add('active');
    } else {
      overlay.classList.remove('active');
    }
  }).observe(chatWindow, { attributes: true, attributeFilter: ['class'] });

  // Clicking overlay closes chatbot
  overlay.addEventListener('click', function() {
    var fab = document.getElementById('chatbotFab');
    if (fab) fab.click();
  });
})();
